const levels = [
  ["0-1 year | Foundation", "definition -> simple example -> basic validation", "fundamental correctness and clear reasoning"],
  ["0-1 year | Foundation", "definition -> simple example -> basic validation", "fundamental correctness and clear reasoning"],
  ["1-3 years | Junior", "requirements -> method -> edge cases -> validation", "independent analysis and careful implementation"],
  ["1-3 years | Junior", "requirements -> method -> edge cases -> validation", "independent analysis and careful implementation"],
  ["3-5 years | Mid-Level", "business goal -> design -> tradeoffs -> metrics", "project ownership, tradeoffs, and production awareness"],
  ["3-5 years | Mid-Level", "business goal -> design -> tradeoffs -> metrics", "project ownership, tradeoffs, and production awareness"],
  ["5-7 years | Senior", "ambiguous goal -> system approach -> risks -> measurable decision", "leadership under ambiguity, scale, and cross-functional delivery"],
  ["5-7 years | Senior", "ambiguous goal -> system approach -> risks -> measurable decision", "leadership under ambiguity, scale, and cross-functional delivery"],
  ["7-10 years | Staff / Lead", "organizational problem -> standards or platform -> adoption -> governance", "cross-team influence and organization-level decision quality"],
  ["10+ years | Principal / Architect", "business strategy -> decision framework -> quantified uncertainty -> durable ownership", "enterprise direction, executive communication, and durable business impact"],
];

function render(ep) {
  const lines = [
    `# Episode ${ep.number}: ${ep.title}`,
    "",
    `YouTube title: Data Science Mock Interview Practice | Episode ${ep.number}: ${ep.title}`,
    "",
    "Estimated duration: 22-28 min",
    "",
    "Source round: Python Full Stack to GenAI, ML, and Data Scientist Career Path",
    "",
    `Focus: ${ep.focus}`,
    "",
    "## Opening",
    "",
    "Hi everyone, welcome back to the Data Science Mock Interview Practice series.",
    "",
    `In today's episode, we are practicing ${ep.title}. Questions increase from foundation level to principal-level judgment.`,
    "",
    "Pause after each question and answer aloud. Clarify definitions and assumptions, show your method, discuss risks and limitations, and finish with how the result would support a decision.",
    "",
    "---",
  ];

  ep.questions.forEach((question, index) => {
    const [level, structure, checks] = levels[index];
    lines.push(
      "",
      `## Question ${index + 1}`,
      "",
      `Experience level: ${level}`,
      "",
      "Interviewer:",
      question,
      "",
      "Pause the video and answer this question aloud.",
      "",
      "Senior Associate answer guide:",
      `${ep.guide} For this ${level} question, the answer should demonstrate ${checks}. Include a concrete example, the most important assumption or failure risk, and the evidence you would use to validate the conclusion.`,
      "",
      "Senior answer structure:",
      `Use this structure: ${structure}.`,
      "",
      "Scenario-based practice:",
      `Apply the question to a realistic product or business situation. Explain the context, data, method, tradeoff, validation, recommendation, and ownership for: ${question}`,
      "",
      "What interviewer checks:",
      `They are checking ${checks}, plus whether you connect technical analysis to a defensible business decision.`,
      "",
      "---",
    );
  });

  lines.push(
    "",
    "## Closing",
    "",
    `That completes Episode ${ep.number}: ${ep.title}.`,
    "",
    "Repeat the questions without reading the guides. For each answer, state the decision, assumptions, method, tradeoffs, validation evidence, limitations, and next action.",
    "",
  );
  return lines.join("\n");
}

for (const episode of episodes) {
  if (episode.questions.length !== 10) throw new Error(`Episode ${episode.number} must contain 10 questions`);
  fs.writeFileSync(
    path.join(outDir, `episode-${episode.number}-${episode.slug}.md`),
    render(episode),
  );
}
